Here is `mars_weather_fetcher.py` — a stdlib-only Python client for the NASA Mars weather APIs. No pip. Runs on GitHub Actions or bare cron.

```python
#!/usr/bin/env python3
"""mars_weather_fetcher.py — Fetch Mars weather from NASA InSight/MEDA APIs.

Stdlib only. No pip. Designed for GitHub Actions cron.
Falls back to MEDA (Perseverance) if InSight endpoint returns stale data.
"""
from __future__ import annotations

import json
import urllib.request
from datetime import datetime, timezone
from pathlib import Path

INSIGHT_API = "https://api.nasa.gov/insight_weather/"
MEDA_FEED = "https://mars.nasa.gov/rss/api/?feed=weather&category=msl&feedtype=json"
DEFAULT_KEY = "DEMO_KEY"


def fetch_insight(api_key: str = DEFAULT_KEY) -> dict:
    url = f"{INSIGHT_API}?api_key={api_key}&feedtype=json&ver=1.0"
    req = urllib.request.Request(url, headers={"Accept": "application/json"})
    with urllib.request.urlopen(req, timeout=30) as resp:
        return json.loads(resp.read().decode())


def fetch_meda_latest() -> list[dict]:
    req = urllib.request.Request(MEDA_FEED, headers={"Accept": "application/json"})
    with urllib.request.urlopen(req, timeout=30) as resp:
        data = json.loads(resp.read().decode())
    return data.get("soles", [])[:7]


def _safe_float(v) -> float | None:
    try:
        return float(v)
    except (TypeError, ValueError):
        return None


def parse_insight(data: dict) -> list[dict]:
    readings = []
    for sol in data.get("sol_keys", []):
        e = data.get(sol, {})
        at, pre, hws = e.get("AT", {}), e.get("PRE", {}), e.get("HWS", {})
        readings.append({
            "sol": int(sol), "source": "insight",
            "temp_avg_c": _safe_float(at.get("av")),
            "temp_min_c": _safe_float(at.get("mn")),
            "temp_max_c": _safe_float(at.get("mx")),
            "pressure_pa": _safe_float(pre.get("av")),
            "wind_ms": _safe_float(hws.get("av")),
            "season": e.get("Season"),
            "first_utc": e.get("First_UTC"),
            "last_utc": e.get("Last_UTC"),
        })
    return sorted(readings, key=lambda r: r["sol"], reverse=True)


def parse_meda(soles: list[dict]) -> list[dict]:
    readings = []
    for s in soles:
        mn, mx = _safe_float(s.get("min_temp")), _safe_float(s.get("max_temp"))
        avg = round((mn + mx) / 2, 1) if mn is not None and mx is not None else mn or mx
        readings.append({
            "sol": int(s.get("sol", 0)), "source": "meda",
            "temp_avg_c": avg, "temp_min_c": mn, "temp_max_c": mx,
            "pressure_pa": _safe_float(s.get("pressure")),
            "wind_ms": None, "season": s.get("season"),
            "first_utc": s.get("First_UTC"), "last_utc": s.get("Last_UTC"),
        })
    return sorted(readings, key=lambda r: r["sol"], reverse=True)


def format_forecast(readings: list[dict]) -> str:
    if not readings:
        return "No weather data available."
    latest = readings[0]
    lines = [
        f"## Sol {latest['sol']} Weather — {latest['source'].upper()}",
        f"Season: **{latest.get('season', 'unknown')}**", "",
        "| Metric | Value |", "|--------|-------|",
    ]
    if latest["temp_avg_c"] is not None:
        lines.append(f"| Avg temp | {latest['temp_avg_c']:.1f} °C |")
    if latest["temp_min_c"] is not None:
        lines.append(f"| Low | {latest['temp_min_c']:.1f} °C |")
    if latest["temp_max_c"] is not None:
        lines.append(f"| High | {latest['temp_max_c']:.1f} °C |")
    if latest["pressure_pa"] is not None:
        lines.append(f"| Pressure | {latest['pressure_pa']:.0f} Pa |")
    if latest["wind_ms"] is not None:
        lines.append(f"| Wind | {latest['wind_ms']:.1f} m/s |")
    lines.append(f"\n*Fetched {datetime.now(timezone.utc):%Y-%m-%d %H:%M UTC}*")
    return "\n".join(lines)


def fetch_and_format(api_key: str = DEFAULT_KEY) -> str:
    data = fetch_insight(api_key)
    readings = parse_insight(data)
    if not readings:
        readings = parse_meda(fetch_meda_latest())
    return format_forecast(readings)


if __name__ == "__main__":
    print(fetch_and_format())
```

**Design decisions:**

1. **Dual-source fallback** — InSight is primary (richer data: wind, pressure, temp). If InSight returns empty (lander dormant since late 2022), falls back to MEDA/Perseverance data from the public Mars RSS feed.
2. **Common schema** — Both sources normalize to identical dict shape. Downstream code never cares which rover produced the data.
3. **`_safe_float` everywhere** — NASA APIs return mixed types (strings, nulls, ints). Every numeric field goes through defensive parsing.
4. **stdlib only** — `urllib.request` for HTTP, `json` for parsing. Zero deps. Runs in any GitHub Actions runner without setup.

